#include "server/commands/appe.h"
#include "common/response_code.h"
#include "common/session.h"
#include "server/command_support.h"
#include <filesystem>
namespace yuan::net::ftp { REGISTER_COMMAND_IMPL(CommandAppe); FtpCommandResponse CommandAppe::execute(FtpSession *session, const std::string &args) { FtpCommandResponse denied{FtpResponseCode::invalid, ""}; if (!ensure_login(session, denied)) { return denied; } if (args.empty()) { return {FtpResponseCode::__501__, "File name is required."}; } if (!session->get_passive_addr().has_value()) { return {FtpResponseCode::__425__, "Use PASV before APPE."}; } auto path = resolve_path(session, args); if (!path_within_root(session, path)) { return {FtpResponseCode::__550__, "Target path is not allowed."}; } std::error_code ec; std::filesystem::create_directories(path.parent_path(), ec); if (ec) { return {FtpResponseCode::__550__, "Cannot create target directory."}; } std::size_t existing = std::filesystem::exists(path) ? static_cast<std::size_t>(std::filesystem::file_size(path)) : 0; std::size_t offset = static_cast<std::size_t>(session->get_item_value<int32_t>("restart_offset")); if (offset == 0) { offset = existing; } std::size_t appendSize = static_cast<std::size_t>(session->get_item_value<int32_t>("upload_file_size")); FtpFileInfo info; info.mode_ = StreamMode::Receiver; info.dest_name_ = path.generic_string(); info.file_size_ = offset + appendSize; info.current_progress_ = offset; info.append_mode_ = true; info.ready_ = true; session->get_file_manager()->reset(); session->get_file_manager()->add_file(info); auto *file = session->get_file_manager()->get_next_file(); if (!file || !session->set_work_file(file)) { session->clear_passive_addr(); return {FtpResponseCode::__425__, "Passive data connection is not ready."}; } session->remove_item("restart_offset"); return {FtpResponseCode::__150__, "Ready to append file data."}; } CommandType CommandAppe::get_command_type() { return CommandType::cmd_appe; } std::string CommandAppe::get_comand_name() { return "APPE"; } }
